import React, { useEffect, useRef, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';

/* ─── Reveal Hook ───────────────── */
function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;

    const obs = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          obs.disconnect();
        }
      },
      { threshold: 0.15 }
    );

    obs.observe(el);
    return () => obs.disconnect();
  }, []);

  return [ref, visible];
}

/* ─── Reveal Wrapper ───────────── */
function Reveal({ children, delay = 0 }) {
  const [ref, visible] = useReveal();

  return (
    <div
      ref={ref}
      style={{
        opacity: visible ? 1 : 0,
        transform: visible ? 'translateY(0)' : 'translateY(25px)',
        transition: `all 0.7s cubic-bezier(.22,1,.36,1) ${delay}s`,
      }}
    >
      {children}
    </div>
  );
}

/* ─── Counter ─────────────────── */
function Counter({ label, to }) {
  const [count, setCount] = useState(0);
  const [ref, visible] = useReveal();

  useEffect(() => {
    if (!visible) return;

    let start = 0;
    const step = Math.ceil(to / 60);

    const t = setInterval(() => {
      start += step;
      if (start >= to) {
        setCount(to);
        clearInterval(t);
      } else setCount(start);
    }, 20);

    return () => clearInterval(t);
  }, [visible, to]);

  return (
    <div ref={ref} style={{ textAlign: 'center' }}>
      <h2>{count}+</h2>
      <p style={{ color: 'var(--text-secondary)' }}>{label}</p>
    </div>
  );
}

/* ─── Main ───────────────────── */
export default function Home() {
  const { user } = useAuth();
  const navigate = useNavigate();

  const dashboards = {
    student: '/student',
    company: '/company',
    admin: '/admin',
  };

  const features = [
    { icon: '💼', title: 'Smart Job Matching', desc: 'AI matches students with ideal jobs.' },
    { icon: '🧠', title: 'AI Career Advisor', desc: 'Personalized career guidance in real-time.' },
    { icon: '📄', title: 'CV Analyzer', desc: 'Instant CV feedback & scoring system.' },
    { icon: '📚', title: 'Learning Hub', desc: 'Courses, lessons & certifications.' },
    { icon: '🤝', title: 'Mentorship', desc: 'Connect with industry mentors.' },
    { icon: '🏆', title: 'Gamification', desc: 'Earn points, badges & achievements.' },
  ];

  return (
    <div style={{ background: 'var(--bg-base)' }}>

      {/* HERO */}
      <section style={{ minHeight: '90vh', display: 'flex', alignItems: 'center', padding: '120px 40px' }}>
        <div style={{ maxWidth: 1000, margin: '0 auto', textAlign: 'center' }}>

          <Reveal>
            <h1 style={{ fontSize: '3rem', fontWeight: 800 }}>
              Bridge the Gap Between <span style={{ color: 'var(--accent-primary)' }}>Students</span> & Careers
            </h1>
          </Reveal>

          <Reveal delay={0.2}>
            <p style={{ marginTop: 20, color: 'var(--text-secondary)' }}>
              A smart platform combining AI, job matching, learning, and mentorship to help students get hired faster.
            </p>
          </Reveal>

          <Reveal delay={0.4}>
            <div style={{ marginTop: 30, display: 'flex', gap: 12, justifyContent: 'center' }}>
              {user ? (
                <button className="btn btn-primary" onClick={() => navigate(dashboards[user.role])}>
                  Go to Dashboard
                </button>
              ) : (
                <>
                  <Link to="/register" className="btn btn-primary">Get Started</Link>
                  <Link to="/login" className="btn btn-ghost">Sign In</Link>
                </>
              )}
            </div>
          </Reveal>

        </div>
      </section>

      {/* FEATURES */}
      <section style={{ padding: '80px 40px' }}>
        <div style={{ maxWidth: 1100, margin: '0 auto' }}>
          <h2 style={{ textAlign: 'center', marginBottom: 40 }}>Platform Features</h2>

          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3,1fr)', gap: 20 }}>
            {features.map((f, i) => (
              <Reveal key={i} delay={i * 0.1}>
                <div className="card">
                  <div style={{ fontSize: 28 }}>{f.icon}</div>
                  <h3>{f.title}</h3>
                  <p style={{ color: 'var(--text-secondary)' }}>{f.desc}</p>
                </div>
              </Reveal>
            ))}
          </div>
        </div>
      </section>

      {/* STATS */}
      <section style={{ padding: '80px 40px', textAlign: 'center' }}>
        <div style={{ display: 'flex', justifyContent: 'center', gap: 60 }}>
          <Counter label="Students" to={1500} />
          <Counter label="Companies" to={300} />
          <Counter label="Jobs" to={5000} />
          <Counter label="Courses" to={120} />
        </div>
      </section>

      {/* CTA */}
      <section style={{ padding: '80px 40px', textAlign: 'center' }}>
        <h2>Start Your Career Journey Today</h2>
        <p style={{ color: 'var(--text-secondary)' }}>Join StudentBridge and unlock your future</p>

        <Link to="/register" className="btn btn-primary" style={{ marginTop: 20 }}>
          Get Started
        </Link>
      </section>

    </div>
  );
}
